('computer-science:1-2-8-compression:exam:11f08314', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'exam', 'mcq', 1, '{"num": "C1", "question": "<p>Tick (✓) <strong>one</strong> box to identify the statement that correctly defines lossy compression.</p>", "options": ["It permanently removes some data, so the original file cannot be restored exactly", "It removes no data at all, so the original file can be restored exactly", "It only ever works on text files and program code", "It always produces a larger file than the original, uncompressed file"], "hint": "Think about what happens to the DATA itself, not just the file size."}'::jsonb, '{"answer": 0, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>It permanently removes some data, so the original file cannot be restored exactly</strong> (box 1)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "It permanently removes some data, so the original file cannot be restored exactly."}'::jsonb),
('computer-science:1-2-8-compression:exam:a20bacf2', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'exam', 'mcq', 1, '{"num": "C2", "question": "<p>Tick (✓) <strong>one</strong> box to identify the statement that correctly defines lossless compression.</p>", "options": ["It removes data at random until the file reaches an acceptable size", "It removes no data at all, so the original file can be reconstructed exactly", "It can only be applied to files smaller than 1 megabyte", "It always achieves a bigger size reduction than lossy compression"], "hint": "Lossless means exactly what it says — nothing is lost."}'::jsonb, '{"answer": 1, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>It removes no data at all, so the original file can be reconstructed exactly</strong> (box 2)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "It removes no data at all, so the original file can be reconstructed exactly."}'::jsonb),
('computer-science:1-2-8-compression:exam:219c547b', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'exam', 'mcq', 1, '{"num": "C12", "question": "<p>Tick (✓) <strong>one</strong> box to identify a real-world example of a LOSSLESS compression format.</p>", "options": ["JPEG, commonly used for photographs on the web", "MP3, commonly used for music and audio files", "ZIP, commonly used for documents and program files", "A format that always discards half of an image''s pixels"], "hint": "Three of these options are either lossy formats or aren''t real formats at all."}'::jsonb, '{"answer": 2, "markScheme": "<div class=\"marks-section\">\n<h5>Mark Scheme — 1 mark</h5>\n<ul>\n<li><strong>ZIP, commonly used for documents and program files</strong> (box 3)</li>\n</ul>\n</div>\n<div class=\"marks-section\">\n<h5>How the marks are given</h5>\n<ul>\n<li>Only the correct option scores; 2 or more ticks scores 0.</li>\n</ul>\n</div>", "modelAnswer": "ZIP, commonly used for documents and program files."}'::jsonb),
('computer-science:1-2-8-compression:mcq:c876a1b6', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "What is the main effect of compressing a computer file?", "options": ["The file becomes password protected so that only certain people can open it", "The file''s size is reduced, so it needs less storage space and transfers faster", "The file''s contents are automatically translated into a completely different language", "The file is permanently deleted from the device and moved into an online backup"]}'::jsonb, '{"answer": 1, "explain": "Compression reduces a file''s size, which means it uses less storage and transfers more quickly — it does not change what the file contains or does."}'::jsonb),
('computer-science:1-2-8-compression:mcq:f199d803', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "Which statement correctly describes lossy compression?", "options": ["It permanently removes some of the original data, so the file cannot be restored exactly afterwards", "It keeps every single piece of the original data, so nothing is ever removed from the file at any point", "It only ever works correctly on text files, and it cannot be applied to any images, audio or video files", "It automatically increases the resolution and quality of an image while shrinking its file size"]}'::jsonb, '{"answer": 0, "explain": "Lossy compression discards some data permanently to shrink the file — that data cannot be recovered, so the original state cannot be restored exactly."}'::jsonb),
('computer-science:1-2-8-compression:mcq:649bbb81', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "Which statement correctly describes lossless compression?", "options": ["It removes any data that the file''s creator marks as unimportant before saving", "It shrinks a file by more than lossy compression does, on the exact same content", "It removes no data at all, so the original file can be reconstructed exactly", "It can only be applied once, and the file cannot be compressed a second time"]}'::jsonb, '{"answer": 2, "explain": "Lossless compression stores the same data more efficiently without discarding anything, so decompressing it gives back exactly the original file."}'::jsonb),
('computer-science:1-2-8-compression:mcq:472217cb', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "Which of these file types would usually be the WORST candidate for lossy compression?", "options": ["A photo taken on a smartphone camera and shared widely across several social media platforms", "Source code for a computer program that a company relies on every day", "A song downloaded onto a phone to listen to during a commute", "A short video clip recorded for a video-sharing app"]}'::jsonb, '{"answer": 1, "explain": "Program code needs every character to be exact — a single permanently altered character from lossy compression could stop the program working, so lossless compression is required instead."}'::jsonb),
('computer-science:1-2-8-compression:mcq:e24e7f4c', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "A streaming service wants users to be able to start watching a film within a couple of seconds. Which type of compression best supports this?", "options": ["Lossless compression, because it guarantees the film''s every pixel is stored exactly", "Lossy compression, because it produces a much smaller file that downloads and streams faster", "No compression at all, because streaming always requires the full, completely uncompressed original file", "Lossless compression, because it always produces a smaller file than lossy compression"]}'::jsonb, '{"answer": 1, "explain": "Lossy compression usually achieves a far bigger size reduction, so the film''s data arrives and can start playing much sooner."}'::jsonb),
('computer-science:1-2-8-compression:mcq:ae667828', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "Which of these is a genuine reason for compressing files before sending them over the internet?", "options": ["Compressed files use less of the network''s limited bandwidth while being sent", "Compressed files can no longer be opened by the person receiving them", "Compressed files are automatically protected from computer viruses during transfer", "Compressed files always arrive at their destination in a completely different format"]}'::jsonb, '{"answer": 0, "explain": "Smaller, compressed files use less bandwidth and transfer faster — a genuine, practical reason for compressing files sent over a network."}'::jsonb),
('computer-science:1-2-8-compression:mcq:bb0c17c9', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "Why is lossless compression essential for a company''s financial spreadsheet, rather than lossy compression?", "options": ["Because spreadsheets are always much larger in file size than photos or videos", "Because lossy compression cannot technically be applied to any file made in office software", "Because every number and formula must remain exact, or the figures could become wrong", "Because spreadsheets need to be compressed twice in a row to reach an acceptable size"]}'::jsonb, '{"answer": 2, "explain": "A spreadsheet''s numbers and formulas must stay perfectly accurate — lossless compression guarantees nothing is altered, whereas lossy compression could corrupt a value."}'::jsonb),
('computer-science:1-2-8-compression:mcq:f31e063b', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "A digital photo is compressed using lossy compression before being emailed. What happens to the photo''s quality?", "options": ["The quality improves, because compression sharpens the details in every pixel", "The quality is unaffected, because lossy compression never changes any pixel data", "The quality is reduced, because some image detail has been permanently discarded", "The quality becomes impossible to predict until the photo is opened again"]}'::jsonb, '{"answer": 2, "explain": "Lossy compression permanently removes some image detail to shrink the file, which reduces quality — even if the loss is often hard to notice."}'::jsonb),
('computer-science:1-2-8-compression:mcq:6986abec', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "Which pair correctly matches a real-world file format to the type of compression it uses?", "options": ["MP3 uses lossless compression, and ZIP uses lossy compression", "JPEG uses lossy compression, and PNG uses lossless compression", "ZIP uses lossy compression, and JPEG uses lossless compression", "PNG uses lossy compression, and MP3 uses lossless compression"]}'::jsonb, '{"answer": 1, "explain": "JPEG is a widely used lossy image format; PNG is a widely used lossless image format — the two are commonly confused in the opposite direction."}'::jsonb),
('computer-science:1-2-8-compression:mcq:236dd191', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "A hospital stores medical scan images that doctors must be able to examine in full, exact detail. Which type of compression should it use?", "options": ["Lossy compression, because doctors will not notice any missing image detail", "No compression at all, because medical images cannot legally be compressed", "Lossless compression, because no detail in the scan can be permanently lost", "Lossy compression, because it is the only method that can be applied to images"]}'::jsonb, '{"answer": 2, "explain": "Where exact detail is critical for a decision (like a medical diagnosis), lossless compression is required so nothing is permanently discarded."}'::jsonb),
('computer-science:1-2-8-compression:mcq:46881e9a', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "What is the main drawback of choosing lossy compression over lossless compression?", "options": ["Lossy compressed files always take up more storage space than the original", "Some of the original file''s data and quality is lost and cannot be recovered", "Lossy compression cannot legally be used for any type of file stored on the internet", "Lossy compressed files always take much longer to transfer over a network"]}'::jsonb, '{"answer": 1, "explain": "The trade-off for lossy compression''s much smaller file size is a permanent, unrecoverable loss of some data and quality."}'::jsonb),
('computer-science:1-2-8-compression:mcq:3f277b21', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'mcq', 'mcq', 1, '{"question": "A word-processed report needs to be edited and re-saved many times without any of its text or formatting being permanently damaged. Which type of compression is appropriate?", "options": ["Lossy compression, since text files are always small enough not to need lossless", "Either type works equally well, since repeatedly editing a document has no real effect on this", "Lossless compression, since every character and formatting detail must be kept exactly", "Lossy compression, since it always compresses text more effectively than lossless"]}'::jsonb, '{"answer": 2, "explain": "A document that must stay exactly correct through repeated edits needs lossless compression, which guarantees nothing is ever permanently lost."}'::jsonb),
('computer-science:1-2-8-compression:tf:802d4462', 'computer-science', 'computer-science:1-2-8-compression', '1.2.8 Compression', 'tf', 'tf', 1, '{"question": "Compression makes a file smaller so it uses less storage and transfers faster."}'::jsonb, '{"answer": true, "explain": "Correct — this is the core purpose of compression."}'::jsonb)
